#include <iostream>
#include <vector>
using namespace std;

int main() {
    int n;
    cin >> n;
    vector<vector<int>> arr(n, vector<int>(2));
    for (int i = 0; i < n; i++) {
        cin >> arr[i][0] >> arr[i][1];
    }
    int res = solve(n, arr.data());
    cout << (res == -1 ? "None" : to_string(res)) << endl;
    return 0;
}

int solve(int n, int arr[][2]) {
    if (!n) return -1;
    for (int i = 0; i < n; i++) {
        if (arr[i][0] == arr[i][1]) return arr[i][1];
    }
    return -1;
}
